import os
import re
import sys

sys.path.insert(0, os.path.dirname(__file__))
from _allow_hook_harness import run_hook, cleanup, fresh_ids

AC_UID = "13caadaeb1385f5c"
AC_TYPE = "hook"


def test_AC11():
    r"""
    GIVEN: a DIFFERENTIAL PAIR of anchored, command-token-bearing regexes that
           differ ONLY in the nested-quantifier shape (so neither can be
           rejected by the universal gate NOR by the under-specified/no-command
           gate — both have a concrete '^git\s+stash' command head and a
           bounded literal; the only thing that can distinguish them is the
           nested-quantifier detector):
             NEGATIVE = r're:^git\s+stash\s+--message=(a+)+$'
                        (nested quantifier (a+)+ -> catastrophic backtracking)
             POSITIVE = r're:^git\s+stash\s+--message=[A-Za-z0-9_-]+$'
                        (bounded char-class, no nested quantifier)
    WHEN:  the hook runs for EACH member of the pair
    THEN:  the NEGATIVE member is REFUSED SPECIFICALLY by the nested-quantifier
           / catastrophic-backtracking detector:
             - legacy_written == False, sentinel_written == False
             - stderr matches  r'nested quantifier|catastrophic backtracking'
             - stderr does NOT match
               r'name an explicit command|under-specified|universal'
             - exit 0
           The POSITIVE member is GRANTED:
             - legacy_written == True, sentinel_written == True, exit 0

    Differential-only distinguisher == nested_quantifier_detector. Because the
    two inputs are identical except for the nested-quantifier shape, this AC can
    ONLY pass if the nested-quantifier detector specifically fires on the
    NEGATIVE and not the POSITIVE. An impl that dropped the detector would GRANT
    both (AC fails); one that over-refused via the universal/under-specified
    gate would refuse both (AC fails).
    """
    negative = r"re:^git\s+stash\s+--message=(a+)+$"
    positive = r"re:^git\s+stash\s+--message=[A-Za-z0-9_-]+$"

    # NEGATIVE: refused SPECIFICALLY by the nested-quantifier detector.
    sid, task_id = fresh_ids()
    try:
        rn = run_hook(f"/allow {negative}", sid, task_id)
        assert rn["exit"] == 0, f"negative: expected exit 0, got {rn['exit']}"
        assert rn["legacy_written"] is False, "negative: no legacy flag"
        assert rn["sentinel_written"] is False, "negative: no sentinel"
        assert re.search(r"nested quantifier|catastrophic backtracking", rn["stderr"]), (
            f"negative must be refused by the nested-quantifier detector; stderr={rn['stderr']!r}")
        assert not re.search(r"name an explicit command|under-specified|universal", rn["stderr"]), (
            f"negative must NOT be refused via the under-specified/universal gate; stderr={rn['stderr']!r}")
    finally:
        cleanup(sid, task_id)

    # POSITIVE: granted (anchored command head, bounded literal, no nested quant).
    sid, task_id = fresh_ids()
    try:
        rp = run_hook(f"/allow {positive}", sid, task_id)
        assert rp["exit"] == 0, f"positive: expected exit 0, got {rp['exit']}"
        assert rp["legacy_written"] is True, f"positive must be GRANTED (legacy); stderr={rp['stderr']!r}"
        assert rp["sentinel_written"] is True, f"positive must be GRANTED (sentinel); stderr={rp['stderr']!r}"
    finally:
        cleanup(sid, task_id)
